import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Summary {
  totalInvoices: number;
  pending: {
    count: number;
    amount: number;
  };
  paid: {
    count: number;
    amount: number;
  };
  overdue: {
    count: number;
    amount: number;
  };
}

interface InvoiceDistribution {
  status: string;
  value: number;
}

interface InvoiceData {
  summary: Summary;
  invoiceDistribution: InvoiceDistribution[];
}

export default function Widget() {
  const invoiceData = response.data as InvoiceData;
  const { summary, invoiceDistribution } = invoiceData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#0D47A1' }}>
              Invoice Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Invoices: {summary.totalInvoices}
            </Typography>
          </Box>

          <Box>
            <PieChart
              height={200}
              series={[
                {
                  data: invoiceDistribution.map(({ status, value }) => ({ label: status, value })),
                  colorScheme: ['#FFC107', '#4CAF50', '#F44336'],
                },
              ]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiPieChart-sector': {
                  stroke: '#FFFFFF',
                  strokeWidth: 2,
                },
                '& .MuiPieChart-label': {
                  fontSize: 12,
                  fill: '#333',
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={2}>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Pending
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {summary.pending.count} (${summary.pending.amount.toFixed(2)})
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Paid
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {summary.paid.count} (${summary.paid.amount.toFixed(2)})
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Overdue
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {summary.overdue.count} (${summary.overdue.amount.toFixed(2)})
              </Typography>
            </Box>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
